import React, { useState } from "react";

export default function App() {
  // ================= PRODUCTS =================
  const PRODUCTS = [
    { id: 1, title: "The Alchemist", price: 199 },
    { id: 2, title: "Sapiens", price: 499 },
    { id: 3, title: "Rich Dad Poor Dad", price: 399 },
  ];

  // ================= STATES =================
  const [cart, setCart] = useState([]);
  const [page, setPage] = useState("home");
  const [user, setUser] = useState(null);

  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
  });

  // ================= AUTH =================
  const register = () => {
    const users = JSON.parse(localStorage.getItem("users") || "{}");

    if (users[form.email]) {
      alert("User already exists");
      return;
    }

    users[form.email] = form;
    localStorage.setItem("users", JSON.stringify(users));

    alert("Registered successfully");
    setPage("login");
  };

  const login = () => {
    const users = JSON.parse(localStorage.getItem("users") || "{}");

    if (!users[form.email] || users[form.email].password !== form.password) {
      alert("Invalid credentials");
      return;
    }

    setUser(users[form.email]);
    setPage("home");
  };

  const logout = () => {
    setUser(null);
  };

  // ================= CART =================
  const addToCart = (product) => {
    const exists = cart.find((c) => c.id === product.id);

    if (exists) {
      setCart(
        cart.map((c) =>
          c.id === product.id ? { ...c, qty: c.qty + 1 } : c
        )
      );
    } else {
      setCart([...cart, { ...product, qty: 1 }]);
    }
  };

  // ================= UI =================
  return (
    <div style={{ padding: 20, fontFamily: "Arial" }}>

      {/* NAVBAR */}
      <div style={{ display: "flex", justifyContent: "space-between", background: "#3f8bef", color: "white", padding: 10 }}>
        <h2 onClick={() => setPage("home")} style={{ cursor: "pointer" }}>
          📚 Book Heaven
        </h2>

        <div>
          {user ? (
            <>
              👤 {user.name} | 
              <button onClick={logout}>Logout</button>
            </>
          ) : (
            <>
              <button onClick={() => setPage("login")}>Login</button>
              <button onClick={() => setPage("register")}>Register</button>
            </>
          )}
          {"  "}🛒 {cart.length}
        </div>
      </div>

      {/* ================= HOME ================= */}
      {page === "home" && (
        <>
          <h2>Books</h2>
          <div style={{ display: "flex", gap: 20 }}>
            {PRODUCTS.map((p) => (
              <div key={p.id} style={{ border: "1px solid #ccc", padding: 10 }}>
                <h4>{p.title}</h4>
                <p>₹{p.price}</p>
                <button onClick={() => addToCart(p)}>Add</button>
              </div>
            ))}
          </div>

          <h2>Cart</h2>
          {cart.map((item) => (
            <p key={item.id}>
              {item.title} x {item.qty}
            </p>
          ))}
        </>
      )}

      {/* ================= LOGIN ================= */}
      {page === "login" && (
        <div>
          <h2>Login</h2>
          <input
            placeholder="Email"
            onChange={(e) => setForm({ ...form, email: e.target.value })}
          />
          <br />
          <input
            type="password"
            placeholder="Password"
            onChange={(e) => setForm({ ...form, password: e.target.value })}
          />
          <br />
          <button onClick={login}>Login</button>
        </div>
      )}

      {/* ================= REGISTER ================= */}
      {page === "register" && (
        <div>
          <h2>Register</h2>
          <input
            placeholder="Name"
            onChange={(e) => setForm({ ...form, name: e.target.value })}
          />
          <br />
          <input
            placeholder="Email"
            onChange={(e) => setForm({ ...form, email: e.target.value })}
          />
          <br />
          <input
            type="password"
            placeholder="Password"
            onChange={(e) => setForm({ ...form, password: e.target.value })}
          />
          <br />
          <button onClick={register}>Register</button>
        </div>
      )}
    </div>
  );
}
